export type ExportNamespacesData = {
    body?: never;
    path?: never;
    query?: {
        /**
         * Namespace's filter
         *
         *
         * Filter field receives a base64 enconded JSON object for limit a search.
         * The JSON object should have a property called `type`, it will filter by a `property` called `devices` where the value should be 'gt' `0`.
         *
         * An example of JSON object will looks like this:
         *
         * ```json
         * [
         * {
         * "type":"property",
         * "params":
         * {
         * "name":"devices",
         * "operator":"eq",
         * "value":"0"
         * }
         * }
         * ]
         * ```
         *
         * So, the output encoded string will result on:
         * `W3sidHlwZSI6InByb3BlcnR5IiwicGFyYW1zIjp7Im5hbWUiOiJkZXZpY2VzIiwib3BlcmF0b3IiOiJndCIsInZhbHVlIjoiMCJ9fV0=`
         *
         */
        filter?: string;
        /**
         * Page number
         */
        page?: number;
        /**
         * Items per page
         */
        per_page?: number;
    };
    url: '/admin/api/export/namespaces';
};

export type ExportNamespacesErrors = {
    /**
     * Unauthorized
     */
    401: {
        /**
         * Error message
         */
        message?: string;
    };
    /**
     * Internal error
     */
    500: {
        /**
         * Error message.
         */
        message?: string;
    };
};

export type ExportNamespacesError = ExportNamespacesErrors[keyof ExportNamespacesErrors];

export type ExportNamespacesResponses = {
    /**
     * Success to export namespaces.
     */
    200: Blob | File;
    /**
     * No content.
     */
    204: void;
};

export type ExportNamespacesResponse = ExportNamespacesResponses[keyof ExportNamespacesResponses];

